              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
            </div>
            <div>
              <p className="text-sm font-bold text-slate-400 uppercase tracking-wider">{t.overdue || 'Overdue'}</p>
              <h3 className="text-2xl font-black text-slate-800">{overdueCount}</h3>
            </div>
          </div>
          <div className="premium-card p-5 bg-white border border-slate-100 flex items-center gap-4">
            <div className="w-12 h-12 rounded-full bg-amber-50 text-amber-500 flex items-center justify-center">
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
            </div>
            <div>
              <p className="text-sm font-bold text-slate-400 uppercase tracking-wider">{t.due_week || 'Due This Week'}</p>
              <h3 className="text-2xl font-black text-slate-800">{dueThisWeekCount}</h3>
            </div>
          </div>
          <div className="premium-card p-5 bg-white border border-slate-100 flex items-center gap-4">
            <div className="w-12 h-12 rounded-full bg-emerald-50 text-emerald-500 flex items-center justify-center">
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
            </div>
            <div>
              <p className="text-sm font-bold text-slate-400 uppercase tracking-wider">{t.completed || 'Completed'}</p>
              <h3 className="text-2xl font-black text-slate-800">{completedCount}</h3>
