            <h3 className="font-bold text-slate-700 uppercase tracking-tight">{t.active_decisions || 'Active Decisions & Actions'}</h3>
            <div className="flex flex-wrap items-center gap-3">
              <input 
                type="text" 
                placeholder={lang === 'fr' ? 'Rechercher...' : 'Quick search...'} 
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
                className="px-4 py-2 border border-slate-200 bg-white rounded-xl text-sm focus:ring-2 focus:ring-indigo-500/20 outline-none w-full sm:w-auto" 
              />
              <div className="flex items-center gap-2">
                <button 
                    onClick={() => setShowAddForm(true)}
                    className="bg-indigo-600 text-white px-5 py-2 rounded-xl text-xs font-black shadow-lg shadow-indigo-500/20 hover:bg-indigo-700 transition-all uppercase tracking-widest whitespace-nowrap"
                >
                    {t.new_btn || '+ Add Action'}
                </button>
                <button 
                    onClick={handleGenerateReport}
                    className="bg-white text-slate-700 border border-slate-200 px-5 py-2 rounded-xl text-xs font-black shadow-sm hover:bg-slate-50 transition-all uppercase tracking-widest whitespace-nowrap"
                >
                    {t.gen_report || 'Report'}
                </button>
              </div>
            </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-white border-b border-slate-100 text-xs uppercase tracking-wider text-slate-400">
                  <th className="px-6 py-4 font-bold">{t.th_item || 'Action Item'}</th>
                  <th className="px-6 py-4 font-bold">{t.th_owner || 'Owner'}</th>
                  <th className="px-6 py-4 font-bold">{t.th_deadline || 'Deadline'}</th>
                  <th className="px-6 py-4 font-bold">{t.th_status || 'Status'}</th>
                  <th className="px-6 py-4 font-bold text-right">{t.th_options || 'Options'}</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {loading ? (
                  <tr><td colSpan={5} className="px-6 py-8 text-center text-slate-500">{t.loading || 'Loading registry...'}</td></tr>
                ) : filteredActions.length === 0 ? (
                  <tr><td colSpan={5} className="px-6 py-8 text-center text-slate-500">{t.no_actions || 'No actions recorded.'}</td></tr>
                ) : (
                  filteredActions.map(act => {
                    const isOverdue = new Date(act.due_date) < now && act.status !== 'Completed';
                    return (
                      <tr key={act.id} className={isOverdue ? "bg-red-50/30" : "hover:bg-slate-50/50 transition-colors"}>
                        <td className="px-6 py-4">
                          <p className="text-sm font-bold text-slate-800">{act.title}</p>
                          <p className="text-xs text-slate-500 mt-1">{t.priority || 'Priority'}: {act.priority}</p>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-2">
                            <div className="w-8 h-8 rounded-full bg-slate-100 text-slate-600 flex items-center justify-center text-xs font-bold shrink-0 border border-slate-200">
                              {(act.assigned_first_name?.[0] || act.assigned_username?.[0] || '?').toUpperCase()}
                            </div>
                            <div className="flex flex-col min-w-0">
                                <span className="text-sm font-bold text-slate-700 truncate">
                                  {act.assigned_first_name || act.assigned_last_name 
                                    ? `${act.assigned_first_name || ''} ${act.assigned_last_name || ''}`.trim()
                                    : act.assigned_username}
                                </span>
                                {act.assigned_first_name && (
                                  <span className="text-[10px] text-slate-400 font-medium">@{act.assigned_username}</span>
                                )}
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`text-sm font-bold ${isOverdue ? 'text-red-600' : 'text-slate-600'}`}>
                            {new Date(act.due_date).toLocaleDateString()}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`badge text-xs px-2 py-1 rounded ring-1 ${
                            act.status === 'Completed' ? 'bg-emerald-100 text-emerald-700 ring-emerald-200' :
                            isOverdue ? 'bg-red-100 text-red-700 ring-red-200' :
                            'bg-blue-100 text-blue-700 ring-blue-200'
                          }`}>
                            {isOverdue && act.status !== 'Completed' ? (t.overdue || 'Overdue') : act.status}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-right whitespace-nowrap">
                          <div className="flex items-center justify-end gap-2">
                            {act.status !== 'Completed' ? (
                              <button 
                                onClick={async () => {
                                  try {
                                    await axios.put(`/api/actions/${act.id}`, { status: 'Completed' }, {
                                      headers: { Authorization: `Bearer ${token}` }
                                    });
                                    fetchData();
                                  } catch (err: any) {
                                    alert(err.response?.data?.error || "Unauthorized to update this directive.");
                                  }
                                }}
                                className="text-xs font-black text-emerald-600 hover:text-emerald-800 uppercase tracking-widest bg-emerald-50 px-3 py-1.5 rounded-lg transition-all hover:bg-emerald-100 active:scale-95"
                              >
                                {t.mark_complete || (lang === 'fr' ? 'Terminer' : 'Mark Complete')}
                              </button>
                            ) : (
                              <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest mr-2">{t.completed || 'Completed'}</span>
                            )}

                            {user?.role === 'Admin' && (
                              <button 
                                onClick={() => handleDeleteAction(act.id)}
                                className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                title={lang === 'fr' ? 'Supprimer' : 'Delete'}
                              >
                                🗑️
                              </button>
                            )}
                          </div>
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Actions;

import { useState, useEffect } from 'react';
import axios from 'axios';
import type { User } from '../App';

interface CalendarEvent {
  id: number;
  title: string;
  description: string;
  start_time: string;
  end_time: string;
  priority: string;
  user_id: number;
}

interface CalendarProps {
  user: User | null;
  lang: 'en' | 'fr';
  translations: any;
  token: string | null;
}

const Calendar = ({ lang, translations, token }: CalendarProps) => {
  const t = translations?.[lang]?.calendar || translations?.['en']?.calendar || {};
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddForm, setShowAddForm] = useState(false);
  const [view, setView] = useState<'calendar' | 'attendance'>('calendar');
  const [leaveRequests, setLeaveRequests] = useState<any[]>([]);
  const [showLeaveModal, setShowLeaveModal] = useState(false);
  const [newLeave, setNewLeave] = useState({
    type: 'Annual',
    start: '',
    end: '',
    reason: ''
  });
  const [error, setError] = useState('');

  const [formData, setFormData] = useState({
    title: '',
    description: '',
    start_time: '',
    end_time: '',
    priority: 'Medium',
    mandatory_attendees: [] as string[],
    optional_attendees: [] as string[]
  });

  const fetchEvents = async () => {
    if (!token) return;
    try {
      setLoading(true);
      const response = await axios.get(`/api/calendar`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setEvents(response.data);
    } catch (err) {
      console.error("Failed to fetch events");
    } finally {
      setLoading(false);
    }
  };

  const fetchUsers = async () => {
    if (!token) return;
    try {
      const res = await axios.get('/api/users', { headers: { Authorization: `Bearer ${token}` } });
      setUsers(res.data);
    } catch {}
  };

  const fetchLeaveRequests = async () => {
    if (!token) return;
    try {
      const response = await axios.get('/api/leaves', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setLeaveRequests(response.data);
    } catch (error) {}
  };

  useEffect(() => {
    fetchEvents();
    fetchUsers();
    fetchLeaveRequests();
  }, [token, lang]);

  const toggleAttendee = (type: 'mandatory' | 'optional', userId: string) => {
    const key = type === 'mandatory' ? 'mandatory_attendees' : 'optional_attendees';
    const other = type === 'mandatory' ? 'optional_attendees' : 'mandatory_attendees';
    const current = formData[key];
    const isSelected = current.includes(userId);
    setFormData(prev => ({
      ...prev,
      [key]: isSelected ? current.filter(id => id !== userId) : [...current, userId],
      // Remove from the other list if added here
      [other]: prev[other].filter(id => id !== userId)
    }));
  };

  const resetForm = () => {
    setFormData({ title: '', description: '', start_time: '', end_time: '', priority: 'Medium', mandatory_attendees: [], optional_attendees: [] });
    setError('');
  };

  const handleAddEvent = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!token) return;
    setError('');

    const start_iso = new Date(formData.start_time);
    const end_iso = new Date(formData.end_time);

    if (end_iso <= start_iso) {
      setError(lang === 'fr' ? "L'heure de fin doit être après l'heure de début" : "End time must be after start time");
      return;
    }

    const conflict = events.find(ev => {
      const evStart = new Date(ev.start_time);
      const evEnd = new Date(ev.end_time);
      return (start_iso < evEnd && end_iso > evStart);
    });

    if (conflict) {
      setError(lang === 'fr'
        ? `Conflit détecté avec : ${conflict.title}`
        : `Smart scheduling detected a conflict with: ${conflict.title}`);
      return;
    }

    try {
      await axios.post(`/api/calendar`, {
        ...formData,
        start_time: start_iso.toISOString(),
        end_time: end_iso.toISOString()
      }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      resetForm();
      setShowAddForm(false);
      fetchEvents();
    } catch (err: any) {
      setError(err.response?.data?.error || (lang === 'fr' ? "Échec de la création. Conflit détecté." : "Failed to create event. Smart scheduling detected a conflict."));
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-white p-4 rounded-3xl shadow-sm border border-slate-100 mb-2">
        <div className="flex items-center gap-4">
           <button 
             onClick={() => setView('calendar')}
             className={`px-5 py-2.5 rounded-2xl text-sm font-bold transition-all border-b-2 ${view === 'calendar' ? 'bg-indigo-600 text-white shadow-lg border-indigo-700' : 'text-slate-500 hover:bg-slate-50 border-transparent font-medium'}`}
           >
             📅 {lang === 'fr' ? 'Calendrier Stratégique' : 'Schedule'}
           </button>
           <button 
             onClick={() => setView('attendance')}
             className={`px-5 py-2.5 rounded-2xl text-sm font-bold transition-all border-b-2 ${view === 'attendance' ? 'bg-indigo-600 text-white shadow-lg border-indigo-700' : 'text-slate-500 hover:bg-slate-50 border-transparent font-medium'}`}
           >
             🕒 {lang === 'fr' ? 'Présence & Congés' : 'Attendance & Leaves'}
           </button>
        </div>
        <button 
          onClick={() => view === 'calendar' ? setShowAddForm(true) : setShowLeaveModal(true)}
          className="bg-indigo-50 text-indigo-600 px-7 py-2.5 rounded-2xl font-black text-xs uppercase tracking-widest border border-indigo-100 hover:bg-indigo-100 transition-all shadow-sm"
        >
          {view === 'calendar' ? (lang === 'fr' ? '+ Ajouter un événement' : '+ New Event') : (lang === 'fr' ? '+ Demander un congé' : '+ Request Leave')}
        </button>
      </div>
      {showAddForm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
