import { useState, useEffect } from 'react';
import axios from 'axios';

interface FinanceRecord {
  id: number;
  title: string;
  amount: number;
  type: string;
  category: string;
  status: string;
  date: string;
  description?: string;
}

interface FinanceProps {
  user: { role: string };
  token: string;
  lang: 'en' | 'fr';
  translations: any;
}

const Finance = ({ token, lang }: FinanceProps) => {
  const [records, setRecords] = useState<FinanceRecord[]>([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [newRecord, setNewRecord] = useState({
    title: '',
    amount: 0,
    type: 'Expense',
    category: 'Operations',
    description: ''
  });

  useEffect(() => {
    fetchRecords();
  }, []);

  const fetchRecords = async () => {
    try {
      const response = await axios.get('/api/finance', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setRecords(response.data);
    } catch (error) {
      console.error("Failed to fetch finance records", error);
    }
  };

  const handleAddRecord = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await axios.post('/api/finance', newRecord, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setShowAddModal(false);
      fetchRecords();
    } catch (error) {
      alert("Failed to add finance record");
    }
  };

  const totalIncome = records.filter(r => r.type === 'Income').reduce((sum, r) => sum + r.amount, 0);
  const totalExpense = records.filter(r => r.type === 'Expense').reduce((sum, r) => sum + r.amount, 0);

  return (
    <div className="space-y-6 fade-in">
      <div className="flex justify-between items-center">
