import { useState, useEffect } from 'react';
import axios from 'axios';

interface Asset {
  id: number;
  name: string;
  serial_number: string;
  category: string;
  value: number;
  status: string;
  assigned_to?: number;
  purchase_date?: string;
  last_maintenance?: string;
}

interface InventoryProps {
  user: { role: string };
  token: string;
  lang: 'en' | 'fr';
  translations: any;
}

const Inventory = ({ user, token, lang }: InventoryProps) => {
  const [assets, setAssets] = useState<Asset[]>([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [newAsset, setNewAsset] = useState({
    name: '',
    serial_number: '',
    category: 'IT',
    value: 0,
    status: 'In Use'
  });

  useEffect(() => {
    fetchAssets();
  }, []);

  const fetchAssets = async () => {
    try {
      const response = await axios.get('/api/assets', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setAssets(response.data);
    } catch (error) {
      console.error("Failed to fetch assets", error);
    }
  };

  const handleAddAsset = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await axios.post('/api/assets', newAsset, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setShowAddModal(false);
      fetchAssets();
    } catch (error) {
      alert("Failed to add asset");
    }
  };

  return (
    <div className="space-y-6 fade-in">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">e-Asset</h2>
          <p className="text-slate-500 font-medium">{lang === 'fr' ? 'Gestion des actifs et de l\'inventaire' : 'Asset & Inventory Management'}</p>
        </div>
        {user.role === 'Admin' && (
          <button 
            onClick={() => setShowAddModal(true)}
            className="bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all flex items-center gap-2"
          >
            <span>+</span> {lang === 'fr' ? 'Ajouter un actif' : 'Add Asset'}
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="premium-card p-6 border-l-4 border-indigo-500">
          <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mb-1">{lang === 'fr' ? 'Valeur Totale' : 'Total Asset Value'}</p>
          <p className="text-3xl font-black text-slate-800">${assets.reduce((sum, a) => sum + a.value, 0).toLocaleString()}</p>
        </div>
        <div className="premium-card p-6 border-l-4 border-amber-500">
          <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mb-1">{lang === 'fr' ? 'Actuels' : 'Active Items'}</p>
          <p className="text-3xl font-black text-slate-800">{assets.length}</p>
        </div>
        <div className="premium-card p-6 border-l-4 border-emerald-500">
          <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mb-1">{lang === 'fr' ? 'En Maintenance' : 'In Maintenance'}</p>
          <p className="text-3xl font-black text-slate-800">{assets.filter(a => a.status === 'Maintenance').length}</p>
        </div>
      </div>

      <div className="premium-card overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest">{lang === 'fr' ? 'Nom' : 'Name'}</th>
              <th className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest">{lang === 'fr' ? 'Catégorie' : 'Category'}</th>
              <th className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest">{lang === 'fr' ? 'Valeur' : 'Value'}</th>
              <th className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest">{lang === 'fr' ? 'Statut' : 'Status'}</th>
              <th className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest">{lang === 'fr' ? 'Actions' : 'Actions'}</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {assets.map(asset => (
              <tr key={asset.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4">
                  <p className="font-bold text-slate-800">{asset.name}</p>
                  <p className="text-[10px] text-slate-400 font-bold">SN: {asset.serial_number}</p>
                </td>
                <td className="px-6 py-4 text-sm font-medium text-slate-600">{asset.category}</td>
                <td className="px-6 py-4 text-sm font-bold text-slate-800">${asset.value.toLocaleString()}</td>
                <td className="px-6 py-4">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${
                    asset.status === 'In Use' ? 'bg-emerald-100 text-emerald-700' : 
                    asset.status === 'Maintenance' ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-600'
                  }`}>
                    {asset.status}
                  </span>
                </td>
                <td className="px-6 py-4">
                   <button className="text-indigo-600 font-bold text-xs hover:underline">Details</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showAddModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="glass premium-card w-full max-w-lg p-8 fade-in-up">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-2xl font-black text-slate-800">{lang === 'fr' ? 'Nouvel Actif' : 'New Asset'}</h3>
              <button onClick={() => setShowAddModal(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>
            <form onSubmit={handleAddAsset} className="space-y-4">
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Name</label>
                <input 
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white/50 focus:outline-none focus:ring-2 focus:ring-indigo-500/20"
                  value={newAsset.name}
                  onChange={e => setNewAsset({...newAsset, name: e.target.value})}
                  required
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Category</label>
                  <select 
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white/50 focus:outline-none focus:ring-2 focus:ring-indigo-500/20"
                    value={newAsset.category}
                    onChange={e => setNewAsset({...newAsset, category: e.target.value})}
                  >
                    <option value="IT">IT Infrastructure</option>
                    <option value="Office">Office Furniture</option>
                    <option value="Vehicle">Vehicle</option>
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Value ($)</label>
                  <input 
                    type="number"
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white/50 focus:outline-none focus:ring-2 focus:ring-indigo-500/20"
                    value={newAsset.value}
                    onChange={e => setNewAsset({...newAsset, value: Number(e.target.value)})}
                    required
                  />
                </div>
              </div>
              <button type="submit" className="w-full bg-indigo-600 text-white font-black py-4 rounded-xl shadow-lg mt-4">
                {lang === 'fr' ? 'Enregistrer l\'actif' : 'Register Asset'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

import { useState } from 'react';
import axios from 'axios';

interface LoginProps {
  onLogin: (u: string, p: string) => Promise<any>;
  authMessage: string;
  lang: 'en' | 'fr';
  setLang: (l: 'en' | 'fr') => void;
  translations: any;
}

const Login = ({ onLogin, authMessage, lang, setLang, translations }: LoginProps) => {
  const t = translations?.[lang]?.auth || translations?.['en']?.auth || {};
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // MFA States
  const [showMfa, setShowMfa] = useState(false);
  const [mfaCode, setMfaCode] = useState('');
  const [mfaUserId, setMfaUserId] = useState<number | null>(null);
  const [mfaChallenge, setMfaChallenge] = useState('');
  const [internalError, setInternalError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setInternalError('');

    const result = await onLogin(username, password);

    if (result?.mfa_required) {
      setMfaUserId(result.user_id);
      setMfaChallenge(result.message);
      setShowMfa(true);
    }

    setIsLoading(false);
  };

  const handleMfaSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setInternalError('');

    try {
      const response = await axios.post('/api/auth/mfa/verify', {
        user_id: mfaUserId,
        code: mfaCode
      });

      const { token, user } = response.data;

      // Manually trigger the app state update since we bypassed handleLogin redirection
      localStorage.setItem('token', token);
      localStorage.setItem('user', JSON.stringify(user));
      window.location.href = '/dashboard'; 
    } catch (error: any) {
      setInternalError(error.response?.data?.error || 'MFA verification failed');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4">
      <div className="glass premium-card w-full max-w-md p-8 md:p-10 fade-in-up animate-float relative overflow-hidden">
        {/* Decorative glowing orb in the card */}
        <div className="absolute -top-20 -right-20 w-40 h-40 bg-indigo-400/20 rounded-full blur-3xl"></div>
        <div className="absolute -bottom-20 -left-20 w-40 h-40 bg-purple-400/20 rounded-full blur-3xl"></div>

        <div className="relative z-10">
          <div className="flex justify-end mb-4">
             <div className="flex rounded-lg border border-slate-200 bg-white/40 overflow-hidden p-0.5 shadow-sm text-[10px] font-bold shrink-0">
                <button 
                  type="button"
                  onClick={() => setLang('en')}
                  className={`px-3 py-1 rounded shadow-sm transition-all ${lang === 'en' ? 'bg-white text-indigo-600' : 'text-slate-500 hover:text-slate-700 bg-transparent'}`}
                >EN</button>
                <button 
                  type="button"
                  onClick={() => setLang('fr')}
                  className={`px-3 py-1 rounded shadow-sm transition-all ${lang === 'fr' ? 'bg-white text-indigo-600' : 'text-slate-500 hover:text-slate-700 bg-transparent'}`}
                >FR</button>
              </div>
          </div>
          <div className="text-center mb-10">
            <div className="w-24 h-24 bg-white/80 rounded-[32px] mx-auto mb-8 flex items-center justify-center p-3 shadow-2xl border border-white/50 backdrop-blur-2xl transform hover:scale-105 transition-all duration-500 group">
              <img src="/logo.png" alt="ePOM Strategic Logo" className="w-full h-full object-contain mix-blend-multiply group-hover:scale-110 transition-transform duration-500" />
            </div>
            <h1 className="text-4xl font-black text-slate-800 tracking-tight mb-2">ePOM</h1>
            <p className="text-slate-500 font-bold text-xs uppercase tracking-[0.2em] opacity-60">{t.subtitle || 'Operational Management Interface'}</p>
          </div>

          {(authMessage || internalError) && (
            <div className="mb-6 p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-600 text-sm font-semibold text-center shimmer">
              {authMessage || internalError}
            </div>
          )}

          {!showMfa ? (
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2 ml-1" htmlFor="username">
                  {t.username || 'Username'}
                </label>
                <input
                  id="username"
                  type="text"
                  placeholder={t.user_ph || "Enter your username"}
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  className="w-full px-5 py-4 rounded-2xl border border-white/40 bg-white/40 text-slate-800 placeholder:text-slate-400 focus:bg-white/70 focus:outline-none focus:ring-4 focus:ring-indigo-400/20 backdrop-blur-md transition-all shadow-sm"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2 ml-1" htmlFor="password">
                  {t.password || 'Password'}
                </label>
                <div className="relative">
                  <input
                    id="password"
                    type={showPassword ? "text" : "password"}
                    placeholder="••••••••"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full px-5 py-4 rounded-2xl border border-white/40 bg-white/40 text-slate-800 placeholder:text-slate-400 focus:bg-white/70 focus:outline-none focus:ring-4 focus:ring-indigo-400/20 backdrop-blur-md transition-all shadow-sm"
                    required
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-indigo-600 transition-colors p-2"
                  >
                    {showPassword ? (
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l18 18"></path></svg>
                    ) : (
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                    )}
                  </button>
                </div>
              </div>

              <button
                type="submit"
                disabled={isLoading}
                className="w-full mt-8 bg-gradient-to-r from-indigo-500 to-purple-600 text-white font-bold py-4 px-6 rounded-2xl shadow-lg shadow-indigo-500/30 hover:shadow-indigo-500/50 hover:-translate-y-1 transition-all active:scale-95 disabled:opacity-70 flex justify-center items-center"
              >
                {isLoading ? (
                  <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                ) : (
                  t.auth_btn || "Authenticate"
                )}
              </button>
            </form>
          ) : (
            <form onSubmit={handleMfaSubmit} className="space-y-6 fade-in">
              <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-xl mb-6">
                <p className="text-xs text-indigo-700 font-bold leading-relaxed">
                  {mfaChallenge}
                </p>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2 ml-1">
                  Verification Code
                </label>
                <input
                  type="text"
                  maxLength={6}
                  placeholder="000000"
                  value={mfaCode}
                  onChange={(e) => setMfaCode(e.target.value.replace(/\D/g, ''))}
                  className="w-full px-5 py-4 rounded-2xl border border-indigo-200 bg-white/60 text-center text-2xl font-black tracking-[0.5em] text-slate-800 focus:bg-white focus:outline-none focus:ring-4 focus:ring-indigo-400/20 backdrop-blur-md transition-all shadow-inner"
                  required
                  autoFocus
                />
              </div>

              <button
                type="submit"
                disabled={isLoading}
                className="w-full mt-8 bg-slate-900 text-white font-bold py-4 px-6 rounded-2xl shadow-lg hover:bg-slate-800 hover:-translate-y-1 transition-all active:scale-95 disabled:opacity-70 flex justify-center items-center"
              >
                {isLoading ? (
                  <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                ) : (
                  "Verify & Access"
                )}
              </button>

              <button 
                type="button"
                onClick={() => setShowMfa(false)}
                className="w-full text-slate-400 text-xs font-bold uppercase tracking-widest hover:text-indigo-600 transition-colors"
              >
                Back to credentials
              </button>
            </form>
          )}

          <div className="mt-8 text-center">
            <p className="text-xs text-slate-400 font-medium tracking-wider uppercase">{t.secure || 'Secure Gateway'}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

