import { useState, useEffect } from 'react';
import axios from 'axios';

interface Message {
  id: number;
  sender_id: number;
  receiver_id?: number | null;
  content: string;
  is_announcement: boolean;
  created_at: string;
  sender_name?: string;
}

interface MessagingProps {
  user: { id: number; username: string; role: string };
  token: string;
  lang: 'en' | 'fr';
  translations: any;
}

const Messaging = ({ user, token }: MessagingProps) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [users, setUsers] = useState<any[]>([]);
  const [targetUser, setTargetUser] = useState<number | 'all'>('all');

  useEffect(() => {
    fetchMessages();
    fetchUsers();
  }, []);

  const fetchMessages = async () => {
    try {
      const response = await axios.get('/api/messages', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setMessages(response.data);
    } catch (error) {}
  };

  const fetchUsers = async () => {
    try {
      const response = await axios.get('/api/users', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setUsers(response.data);
    } catch (error) {}
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim()) return;

    try {
      await axios.post('/api/messages', {
        content: newMessage,
        is_announcement: targetUser === 'all',
        receiver_id: targetUser === 'all' ? null : targetUser
      }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setNewMessage('');
      fetchMessages();
    } catch (error) {
      alert("Failed to send message");
    }
  };

  return (
    <div className="h-[calc(100vh-12rem)] flex gap-6 fade-in">
      {/* Sidebar for conversations/categories */}
      <div className="w-80 flex flex-col gap-4">
        <div className="premium-card p-6 border-l-4 border-indigo-500 bg-indigo-50/30">
          <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs mb-4">Channels</h3>
          <div className="space-y-2">
            <button className="w-full text-left px-4 py-3 rounded-xl bg-white border border-slate-100 font-bold text-slate-800 shadow-sm">
               📢 Announcements
            </button>
            <button className="w-full text-left px-4 py-3 rounded-xl hover:bg-white transition-colors font-medium text-slate-500">
               👥 General Staff
            </button>
          </div>
        </div>

        <div className="premium-card flex-1 p-6 overflow-y-auto">
          <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs mb-4">Direct Messages</h3>
          <div className="space-y-3">
            {users.filter(u => u.id !== user.id).map(u => (
              <button 
                key={u.id}
                onClick={() => setTargetUser(u.id)}
                className={`w-full flex items-center gap-3 px-3 py-2 rounded-xl transition-all ${targetUser === u.id ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'hover:bg-slate-50 text-slate-600'}`}
              >
                <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center font-bold text-xs uppercase">
                  {u.username.charAt(0)}
                </div>
                <div className="text-left">
                  <p className="font-bold text-sm leading-tight">{u.username}</p>
                  <p className="text-[10px] opacity-70 font-bold uppercase tracking-tighter">{u.role}</p>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Main Chat Area */}
      <div className="flex-1 premium-card flex flex-col bg-slate-50/50">
        <div className="p-6 border-b border-slate-100 bg-white flex justify-between items-center">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-2xl bg-indigo-100 text-indigo-600 flex items-center justify-center font-black">
                {targetUser === 'all' ? '📢' : '💬'}
             </div>
             <div>
                <h3 className="font-black text-slate-800 tracking-tight">
                   {targetUser === 'all' ? 'Announcements' : users.find(u => u.id === targetUser)?.username || 'Chat'}
                </h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">
                   {targetUser === 'all' ? 'Company wide broadcasts' : 'Encrypted private channel'}
                </p>
             </div>
          </div>
        </div>

        <div className="flex-1 p-6 overflow-y-auto space-y-6">
          {messages.map(msg => (
            <div key={msg.id} className={`flex ${msg.sender_id === user.id ? 'justify-end' : 'justify-start'}`}>
               <div className={`max-w-[70%] p-4 rounded-2xl shadow-sm ${
                 msg.sender_id === user.id ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white border border-slate-100 text-slate-800 rounded-tl-none'
               }`}>
                  {msg.is_announcement && (
                    <span className="text-[9px] font-black uppercase tracking-widest opacity-70 block mb-1">Official Announcement</span>
                  )}
                  <p className="text-sm font-medium">{msg.content}</p>
                  <div className={`mt-2 flex items-center gap-2 opacity-50 ${msg.sender_id === user.id ? 'justify-end' : 'justify-start'}`}>
                     <span className="text-[9px] font-bold">{msg.sender_name || 'System'}</span>
                     <span className="text-[9px] font-bold">•</span>
                     <span className="text-[9px] font-bold">{new Date(msg.created_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                  </div>
               </div>
            </div>
          ))}
          {messages.length === 0 && (
            <div className="h-full flex items-center justify-center text-slate-400 font-bold italic">
               Start a conversation...
            </div>
          )}
        </div>

        <div className="p-6 bg-white border-t border-slate-100">
           <form onSubmit={handleSendMessage} className="flex gap-4">
              <input 
                 className="flex-1 px-5 py-3 rounded-2xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 bg-slate-50 font-medium text-slate-700"
                 placeholder="Type your message..."
                 value={newMessage}
                 onChange={e => setNewMessage(e.target.value)}
              />
              <button 
                type="submit"
                className="bg-indigo-600 text-white px-8 py-3 rounded-2xl font-black shadow-lg shadow-indigo-100 hover:scale-105 active:scale-95 transition-all"
              >
                 Send
              </button>
           </form>
        </div>
      </div>
    </div>
  );
};

export default Messaging;

import { useState, useEffect } from 'react';
import axios from 'axios';
import type { User } from '../App';

interface ReportsProps {
  user: User | null;
  token: string | null;
  lang: 'en' | 'fr';
  translations: Record<string, any>;
}

const Reports = ({ token, lang, translations }: ReportsProps) => {
  const [loading, setLoading] = useState(true);
  const [metrics, setMetrics] = useState({
    timeUtilization: 0,
    infoVolume: 0,
    decisionRate: 0,
    anomalies: [] as string[],
    briefings: [] as string[]
  });

  const t = translations?.[lang]?.reports || translations?.['en']?.reports || {};

  useEffect(() => {
    const generateAnalytics = async () => {
      try {
        setLoading(true);

        const [calRes, docRes, actRes] = await Promise.all([
          axios.get(`/api/calendar`, { headers: { Authorization: `Bearer ${token}` } }).catch(() => ({data: []})),
          axios.get(`/api/documents`, { headers: { Authorization: `Bearer ${token}` } }).catch(() => ({data: []})),
          axios.get(`/api/actions`, { headers: { Authorization: `Bearer ${token}` } }).catch(() => ({data: []}))
        ]);

        const events = calRes.data;
        const docs = docRes.data;
        const actions = actRes.data;

        // Time Utilization: events this week vs norm
        const timeUtil = events.length > 0 ? Math.min(100, Math.round((events.length / 10) * 100)) : 0;

        // Info Volume: total documents processed
        const infoVol = docs.length;

        // Decision Execution Rate: completed actions / total actions
        const completedActions = actions.filter((a: { status: string }) => a.status === 'Completed').length;
        const execRate = actions.length > 0 ? Math.round((completedActions / actions.length) * 100) : 0;

        // AI Anomaly Detection
        const anomalies: string[] = [];
        const overdue = actions.filter((a: { due_date: string; status: string }) => new Date(a.due_date) < new Date() && a.status !== 'Completed');
        if (overdue.length > 0) {
          anomalies.push(lang === 'fr' 
            ? `${t.anomaly_prefix || 'Détection de'} ${overdue.length} ${t.anomaly_overdue || 'directive(s) critique(s) en retard.'}` 
            : `${t.anomaly_prefix || 'Detected'} ${overdue.length} ${t.anomaly_overdue || 'critical directive(s) overdue.'}`);
        }
        if (events.length > 5) {
          anomalies.push(lang === 'fr'
            ? t.anomaly_density || `La densité du calendrier dépasse l'optimum opérationnel de 15%.`
            : t.anomaly_density || `Schedule density exceeds operational optimum by 15%.`);
        }
        if (anomalies.length === 0) {
          anomalies.push(lang === 'fr' ? (t.no_anomalies || "Opérations normales. Aucune anomalie détectée.") : (t.no_anomalies || "Operations normal. No workflow anomalies detected."));
        }

        // AI Briefing Suggestions
        const briefs: string[] = [];
        const upcomingEvent = events.find((e: { start_time: string; title: string }) => new Date(e.start_time) >= new Date());
        if (upcomingEvent) {
          briefs.push(lang === 'fr'
            ? `${t.briefing_suggested || 'Briefing suggéré : Pré-lecture des métriques pour'} '${upcomingEvent.title}'.`
            : `${t.briefing_suggested || 'Suggested Briefing: Pre-read metrics for'} '${upcomingEvent.title}' event.`);
        } else {
          briefs.push(lang === 'fr'
            ? (t.daily_summary_ready || `Le résumé quotidien de la presse est prêt.`)
            : (t.daily_summary_ready || `Standard Daily Press Summary is ready for review.`));
        }

        setMetrics({
          timeUtilization: timeUtil,
          infoVolume: infoVol,
          decisionRate: execRate,
          anomalies,
          briefings: briefs
        });
      } catch (err) {
        console.error("Failed to fetch analytics");
      } finally {
        setLoading(false);
      }
    };

    generateAnalytics();
  }, [token, lang]);

  return (
    <div className="space-y-6 max-w-7xl">
      <div className="premium-card p-8 fade-in-up border-l-4 border-l-violet-500 bg-gradient-to-r from-white to-violet-50/20">
        <h2 className="text-3xl font-bold text-slate-800 mb-2">{t.title || 'Reports & Analytics'}</h2>
        <p className="text-slate-500 font-medium">{t.subtitle || 'Analytics on time utilization, information volume, and decision execution.'}</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Metric 1 */}
        <div className="premium-card p-6 fade-in-up flex flex-col justify-between" style={{ animationDelay: '0.1s' }}>
          <div>
            <h3 className="text-sm font-bold tracking-widest uppercase text-slate-400 mb-2">{t.time_util || 'Time Utilization'}</h3>
            <div className="flex items-end gap-3 mb-2">
              <span className="text-4xl font-black text-blue-600">{metrics.timeUtilization}%</span>
              <span className="text-sm font-medium text-slate-400 pb-1">{t.capacity || 'capacity'}</span>
            </div>
            <p className="text-xs font-medium text-slate-500 mt-4 leading-relaxed">{t.time_desc || 'Measures strategic alignment of protected scheduling slots versus incoming meeting volumes.'}</p>
          </div>
          <div className="w-full bg-slate-100 h-2 rounded-full mt-6 overflow-hidden">
            <div className="bg-blue-500 h-full rounded-full transition-all duration-1000" style={{width: `${metrics.timeUtilization}%`}}></div>
          </div>
        </div>

        {/* Metric 2 */}
        <div className="premium-card p-6 fade-in-up flex flex-col justify-between" style={{ animationDelay: '0.2s' }}>
          <div>
            <h3 className="text-sm font-bold tracking-widest uppercase text-slate-400 mb-2">{t.info_vol || 'Information Volume'}</h3>
            <div className="flex items-end gap-3 mb-2">
              <span className="text-4xl font-black text-purple-600">{metrics.infoVolume}</span>
              <span className="text-sm font-medium text-slate-400 pb-1">{t.docs_parsed || 'docs parsed'}</span>
            </div>
            <p className="text-xs font-medium text-slate-500 mt-4 leading-relaxed">{t.info_desc || 'Tracks the velocity of standardized briefing notes compiled within the Central Hub.'}</p>
          </div>
        </div>

        {/* Metric 3 */}
        <div className="premium-card p-6 fade-in-up flex flex-col justify-between" style={{ animationDelay: '0.3s' }}>
          <div>
            <h3 className="text-sm font-bold tracking-widest uppercase text-slate-400 mb-2">{t.dec_rate || 'Decision Execution Rate'}</h3>
            <div className="flex items-end gap-3 mb-2">
              <span className="text-4xl font-black text-emerald-500">{metrics.decisionRate}%</span>
              <span className="text-sm font-medium text-slate-400 pb-1">{t.completion || 'completion'}</span>
            </div>
            <p className="text-xs font-medium text-slate-500 mt-4 leading-relaxed">{t.dec_desc || 'Aggregated status of completed workflow objectives versus outstanding tasks assigned.'}</p>
          </div>
          <div className="w-full bg-slate-100 h-2 rounded-full mt-6 overflow-hidden">
            <div className="bg-emerald-500 h-full rounded-full transition-all duration-1000" style={{width: `${metrics.decisionRate}%`}}></div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {/* AI Monitoring */}
        <div className="premium-card p-6 fade-in-up" style={{ animationDelay: '0.4s' }}>
          <div className="flex items-center justify-between mb-6">
            <h3 className="font-bold text-slate-700">{t.ai_title || 'AI-Assisted Workflow Analytics'}</h3>
            <span className="badge bg-indigo-50 text-indigo-700 ring-1 ring-indigo-200">{t.active_mon || 'Active Monitoring'}</span>
          </div>

          {loading ? (
            <div className="text-center p-4 text-slate-400">{t.processing || 'Processing metrics...'}</div>
          ) : (
            <div className="space-y-4">
              <div className="p-4 rounded-xl border border-rose-100 bg-rose-50/50">
                <div className="flex gap-3 mb-2">
                  <span className="text-rose-500">⚠️</span>
                  <h4 className="font-extrabold text-sm text-rose-800">{t.anomaly || 'Anomaly Detection'}</h4>
                </div>
                <ul className="pl-8 list-disc list-outside space-y-1 text-sm font-medium text-rose-700/80">
                  {metrics.anomalies.map((anom, i) => <li key={i}>{anom}</li>)}
                </ul>
              </div>

              <div className="p-4 rounded-xl border border-indigo-100 bg-indigo-50/50">
                <div className="flex gap-3 mb-2">
                  <span className="text-indigo-500">✨</span>
                  <h4 className="font-extrabold text-sm text-indigo-800">{t.briefing_sug || 'Automatic Briefing Suggestions'}</h4>
                </div>
                <ul className="pl-8 list-disc list-outside space-y-1 text-sm font-medium text-indigo-700/80">
                  {metrics.briefings.map((brief, i) => <li key={i}>{brief}</li>)}
                </ul>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Reports;

import { useState } from 'react';
import axios from 'axios';
import type { User } from '../App';

interface SettingsProps {
  user: User | null;
  token: string | null;
  setUser: (user: User | null) => void;
  lang: 'en' | 'fr';
  setLang: (lang: 'en' | 'fr') => void;
  translations: any;
  theme: 'light' | 'dark';
  setTheme: (theme: 'light' | 'dark') => void;
}

const Settings = ({ token, setUser, lang, setLang, translations, theme, setTheme, user: _user }: SettingsProps) => {
  const t = translations?.[lang]?.nav || translations?.['en']?.nav || {};
  const s = translations?.[lang]?.settings || translations?.['en']?.settings || {};

  const [showEditProfile, setShowEditProfile] = useState(false);
  const [isUpdating, setIsUpdating] = useState(false);
  const [profileData, setProfileData] = useState({
    first_name: _user?.first_name || '',
    last_name: _user?.last_name || '',
    email: _user?.email || '',
    username: _user?.username || ''
  });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const handleUpdateProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!_user || !token) return;
    setIsUpdating(true);
    setError('');
    setSuccess('');

    try {
      await axios.put(`/api/users/${_user.id}`, profileData, {
        headers: { Authorization: `Bearer ${token}` }
      });

      const updatedUser = { ..._user, ...profileData };
      setUser(updatedUser);
      localStorage.setItem('user', JSON.stringify(updatedUser));

      setSuccess(lang === 'fr' ? 'Profil mis à jour !' : 'Profile updated successfully!');
      setTimeout(() => {
        setShowEditProfile(false);
        setSuccess('');
      }, 1500);
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to update profile');
    } finally {
      setIsUpdating(false);
    }
  };

  return (
    <div className="space-y-6 max-w-4xl mx-auto">
      <div className="premium-card p-8 fade-in-up">
        <h2 className="text-3xl font-black text-slate-800 mb-2">{t.settings || 'Settings'}</h2>
        <p className="text-slate-500 font-medium">{lang === 'fr' ? 'Préférences et configuration de l\'application.' : 'Application preferences and system configuration.'}</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Language Preferences */}
        <div className="premium-card p-8 fade-in-up" style={{ animationDelay: '0.1s' }}>
          <div className="flex items-center gap-4 mb-6">
            <div className="w-12 h-12 rounded-2xl bg-indigo-50 text-indigo-600 flex items-center justify-center text-2xl shadow-sm">🌍</div>
            <div>
              <h3 className="text-lg font-bold text-slate-800">{s.language || 'Language Preference'}</h3>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{s.display_lang || 'Display Language'}</p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <button 
              onClick={() => setLang('en')}
              className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center gap-2 ${lang === 'en' ? 'border-indigo-500 bg-indigo-50 shadow-md' : 'border-slate-100 hover:border-slate-200 bg-white'}`}
            >
              <span className="text-2xl">🇬🇧</span>
              <span className={`font-bold text-sm ${lang === 'en' ? 'text-indigo-600' : 'text-slate-600'}`}>English</span>
            </button>
            <button 
              onClick={() => setLang('fr')}
              className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center gap-2 ${lang === 'fr' ? 'border-indigo-500 bg-indigo-50 shadow-md' : 'border-slate-100 hover:border-slate-200 bg-white'}`}
            >
              <span className="text-2xl">🇫🇷</span>
              <span className={`font-bold text-sm ${lang === 'fr' ? 'text-indigo-600' : 'text-slate-600'}`}>Français</span>
            </button>
          </div>
        </div>

        {/* System Theme */}
        <div className="premium-card p-8 fade-in-up" style={{ animationDelay: '0.2s' }}>
          <div className="flex items-center gap-4 mb-6">
            <div className="w-12 h-12 rounded-2xl bg-amber-50 text-amber-600 flex items-center justify-center text-2xl shadow-sm">✨</div>
            <div>
              <h3 className="text-lg font-bold text-slate-800">{lang === 'fr' ? 'Apparence' : 'Appearance'}</h3>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{lang === 'fr' ? 'Thème du système' : 'System Theme'}</p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <button 
