                    {lang === 'fr' ? 'Modifier le profil' : 'Edit Profile'}
                 </button>
              </div>
           </div>
        </div>
      </div>

      {showEditProfile && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm shadow-2xl transition-opacity">
