                  type="submit" 
                  disabled={isUpdating}
                  className="flex-1 bg-slate-900 text-white font-black text-xs uppercase tracking-widest py-4.5 rounded-2xl shadow-xl hover:bg-indigo-600 transition-all active:scale-95 disabled:opacity-50"
