                <th className="px-6 py-4 font-black">{t.th_personnel || 'Personnel'}</th>
                <th className="px-6 py-4 font-black">{t.first_name || (lang === 'fr' ? 'Prénom' : 'First Name')}</th>
                <th className="px-6 py-4 font-black">{t.last_name || (lang === 'fr' ? 'Nom' : 'Last Name')}</th>
                <th className="px-6 py-4 font-black">{t.th_role || 'Role'}</th>
                <th className="px-6 py-4 font-black">{t.th_status || 'System Status'}</th>
                {user?.role === 'Admin' && <th className="px-6 py-4 font-black">{t.th_options || 'Options'}</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {loading ? (
                <tr><td colSpan={user?.role === 'Admin' ? 6 : 5} className="px-6 py-8 text-center text-slate-500">{t.loading || 'Loading directory...'}</td></tr>
              ) : users.length === 0 ? (
                <tr><td colSpan={user?.role === 'Admin' ? 6 : 5} className="px-6 py-8 text-center text-slate-500">{t.no_users || 'No personnel found.'}</td></tr>
              ) : (
                users.map((u: UserRecord) => (
                  <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-slate-200 text-slate-600 flex items-center justify-center font-bold text-sm">
                          {u.username.charAt(0).toUpperCase()}
                        </div>
                        <div>
                          <p className="font-bold text-slate-800 leading-tight">{u.username}</p>
                          <p className="text-xs text-slate-500 font-medium">{u.email}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 font-medium text-slate-700 whitespace-nowrap">
                      {u.first_name || '-'}
                    </td>
                    <td className="px-6 py-4 font-medium text-slate-700 whitespace-nowrap">
                      {u.last_name || '-'}
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-md text-xs font-bold ${
                        u.role === 'Admin' ? 'bg-indigo-100 text-indigo-700' :
                        u.role === 'Leader' ? 'bg-purple-100 text-purple-700' :
                        u.role === 'Permanent Secretary' || u.role === 'Deputy Permanent Secretary' ? 'bg-red-100 text-red-700' :
                        u.role === 'Director' || u.role === 'Deputy Director' ? 'bg-orange-100 text-orange-700' :
                        u.role === 'HR' ? 'bg-pink-100 text-pink-700' :
                        u.role === 'Manager' ? 'bg-blue-100 text-blue-700' :
                        u.role === 'Senior Officer' ? 'bg-teal-100 text-teal-700' :
                        'bg-slate-100 text-slate-600'
                      }`}>
                        {(() => {
                           const roleKey = u.role?.toLowerCase().replace(/ /g, '_');
                           return t.roles?.[roleKey] || u.role;
                        })()}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`flex items-center gap-1.5 text-xs font-bold ${u.is_active !== false ? 'text-emerald-500' : 'text-red-500'}`}>
                        <span className={`w-2 h-2 rounded-full ${u.is_active !== false ? 'bg-emerald-500' : 'bg-red-500'}`}></span>
                        {u.is_active !== false ? (t.active || 'ACTIVE') : (t.disabled || 'DISABLED')}
                      </span>
                    </td>
                    {user?.role === 'Admin' && (
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-1.5">
                          <button 
                            onClick={() => startEdit(u)}
                            className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                            title={t.edit || "Edit"}
                          >
                            ✏️
                          </button>
                          <button 
                            onClick={() => handleToggleStatus(u.id, u.is_active !== false)}
                            className={`px-2 py-1 rounded-lg text-xs font-bold transition-colors ${
                              u.is_active !== false
                                ? 'text-amber-600 bg-amber-50 hover:bg-amber-100'
                                : 'text-emerald-600 bg-emerald-50 hover:bg-emerald-100'
                            }`}
                            title={u.is_active !== false ? (lang === 'fr' ? 'Désactiver' : 'Disable') : (lang === 'fr' ? 'Activer' : 'Enable')}
                          >
                            {u.is_active !== false ? (lang === 'fr' ? 'Désactiver' : 'Disable') : (lang === 'fr' ? 'Activer' : 'Enable')}
                          </button>
                          <button 
                            onClick={() => handleDelete(u.id)}
                            className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                            title={lang === 'fr' ? 'Supprimer définitivement' : 'Permanently Delete'}
                          >
                            🗑️
                          </button>
                        </div>
                      </td>
                    )}
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Users;
